FROM jsonb_to_recordset('[{"id": "cap-106-chinese-015", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「 1 冷淡是秋花，更比秋花冷淡些。 2 到處芙蓉供醉賞，從他。自有幽人處士\n誇。    \u0001 3 寂寞兩三葩，晝日無風也帶斜。 4 一片西窗殘照裡，誰家。捲卻湘\n裙薄薄紗。」詞中畫線處，何者最能表達作者不隨流俗、終能獲得賞識的想法？", "options": ["1", "2", "3", "4"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 15, "raw_text": "15. 「 1 冷淡是秋花，更比秋花冷淡些。 2 到處芙蓉供醉賞，從他。自有幽人處士\n    誇。    \u0001 3 寂寞兩三葩，晝日無風也帶斜。 4 一片西窗殘照裡，誰家。捲卻湘\n    裙薄薄紗。」詞中畫線處，何者最能表達作者不隨流俗、終能獲得賞識的想法？\n    (A) 1\n    (B) 2\n    (C) 3\n    (D) 4\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-016", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「友情如一罈醇酒，愈陳愈濃郁醉人。」句中以「醇酒」比喻「友情」的恆久動人。\n下列文句，何者也是用具體事物來比喻抽象概念？", "options": ["沿岸的楓葉以血掌印證，船頭是水雲的故鄉", "圍牆邊綻放的繁花，是造物主所設下的美麗陷阱", "孤獨是一匹衰老的獸，潛伏在我亂石磊磊的心裡", "那蓬鬆的髮，如天空的亂雲，把她襯托得更具風情"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 16, "raw_text": "16. 「友情如一罈醇酒，愈陳愈濃郁醉人。」句中以「醇酒」比喻「友情」的恆久動人。\n     下列文句，何者也是用具體事物來比喻抽象概念？\n     (A)沿岸的楓葉以血掌印證，船頭是水雲的故鄉\n     (B)圍牆邊綻放的繁花，是造物主所設下的美麗陷阱\n     (C)孤獨是一匹衰老的獸，潛伏在我亂石磊磊的心裡\n     (D)那蓬鬆的髮，如天空的亂雲，把她襯托得更具風情\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-017", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "有客語：「馬肝大毒，能殺人，故漢武帝云：『文成食馬肝而死。』」迂公\n適聞之，發笑曰：「客誑語耳，肝故在馬腹中，馬何以不死？」客戲曰：「馬無\n百年之壽，以有肝故也。」公大悟，家有畜馬，便刳其肝，馬立斃。公擲刀歎\n曰：「信哉，毒也。去之尚不可活，況留肝乎？」\n根據這則笑話，下列敘述何者正確？", "options": ["漢武帝因食馬肝而死", "馬肝很毒，所以馬不長壽", "迂公原本不相信客人所說的話", "從迂公殺馬的結果可知客人所言不虛"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 17, "raw_text": "17.     有客語：「馬肝大毒，能殺人，故漢武帝云：『文成食馬肝而死。』」迂公\n      適聞之，發笑曰：「客誑語耳，肝故在馬腹中，馬何以不死？」客戲曰：「馬無\n      百年之壽，以有肝故也。」公大悟，家有畜馬，便刳其肝，馬立斃。公擲刀歎\n      曰：「信哉，毒也。去之尚不可活，況留肝乎？」\n\n      根據這則笑話，下列敘述何者正確？\n      (A)漢武帝因食馬肝而死\n      (B)馬肝很毒，所以馬不長壽\n      (C)迂公原本不相信客人所說的話\n      (D)從迂公殺馬的結果可知客人所言不虛\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-018", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「豔冶之貌，代有之矣；潔朗之操，則人鮮聞。故士矜才則德薄，女衒 1 色則情私。若\n能如執盈，如臨深，則皆為端士淑女矣。」這段文字的觀點，與下列何者最接近？", "options": ["端士淑女應才色兼備 ", "人宜謹飭德操，莫炫耀才色             1.衒：炫示、誇耀", "美貌女子與高潔端士均屬少見", "端士不近美色，淑女不矜才德"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 18, "raw_text": "18. 「豔冶之貌，代有之矣；潔朗之操，則人鮮聞。故士矜才則德薄，女衒 1 色則情私。若\n     能如執盈，如臨深，則皆為端士淑女矣。」這段文字的觀點，與下列何者最接近？\n     (A)端士淑女應才色兼備\n                                 \n     (B)人宜謹飭德操，莫炫耀才色             1.衒：炫示、誇耀\n     (C)美貌女子與高潔端士均屬少見\n     (D)端士不近美色，淑女不矜才德\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-019", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「在國內的醫療系統，所謂的安寧照護還是偏重於生理層面□如何讓一個人在生病與\n往生過程中不要受到太多生理折磨。然而，一個即將往生□面臨生命最後一段歲月的\n人，他們的心理狀態是如何？我們如何從身心靈成長的角度幫助這樣的人？這種心理\n層面上的考慮更是必要。」這段文字□中的標點符號，依序填入下列何者最恰當？", "options": ["…… ，", "―― 、", "； ――", "。  ："], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 19, "raw_text": "19. 「在國內的醫療系統，所謂的安寧照護還是偏重於生理層面□如何讓一個人在生病與\n     往生過程中不要受到太多生理折磨。然而，一個即將往生□面臨生命最後一段歲月的\n     人，他們的心理狀態是如何？我們如何從身心靈成長的角度幫助這樣的人？這種心理\n     層面上的考慮更是必要。」這段文字□中的標點符號，依序填入下列何者最恰當？\n     (A) …… ，\n     (B) ―― 、\n     (C) ； ――\n     (D) 。  ：\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-020", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列文句，何者用字完全正確？", "options": ["這款保養品的效果極佳，才剛上市，名聲便不逕而走", "實驗已接近完成，卻因一時疏忽而功虧一簣，令人惋惜", "廢寢忘食地苦練後，他的演出果然不同反響，贏得滿堂喝采", "昏睡中的乘客面對電車突如奇來的警鈴聲，一時間有些不知所措"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 20, "raw_text": "20.   下列文句，何者用字完全正確？\n      (A)這款保養品的效果極佳，才剛上市，名聲便不逕而走\n      (B)實驗已接近完成，卻因一時疏忽而功虧一簣，令人惋惜\n      (C)廢寢忘食地苦練後，他的演出果然不同反響，贏得滿堂喝采\n      (D)昏睡中的乘客面對電車突如奇來的警鈴聲，一時間有些不知所措\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-021", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "「文學雖然具有普遍性，但因讀者體驗的不同而有變化，讀者倘若沒有類似的\n體驗，它也就失去了效力。」根據這句話，作者認為文學的普遍性要有效力，\n前提最可能是下列何者？", "options": ["讀者的體驗各自不同", "讀者的分布普及各階層", "讀者有類似於作品的經驗", "讀者與作者有相同的喜好"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21. 「文學雖然具有普遍性，但因讀者體驗的不同而有變化，讀者倘若沒有類似的\n     體驗，它也就失去了效力。」根據這句話，作者認為文學的普遍性要有效力，\n     前提最可能是下列何者？\n     (A)讀者的體驗各自不同\n     (B)讀者的分布普及各階層\n     (C)讀者有類似於作品的經驗\n     (D)讀者與作者有相同的喜好\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-022", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "周老師在黑板上寫道：「天下沒有一個人從不羨慕別人，只有少數人從沒被別人羨\n慕過。」她請學生以圖表來表示這句話，下列哪一張圖表最恰當？", "options": ["", "", "", ""], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 22, "raw_text": "22. 周老師在黑板上寫道：「天下沒有一個人從不羨慕別人，只有少數人從沒被別人羨\n    慕過。」她請學生以圖表來表示這句話，下列哪一張圖表最恰當？\n    (A)               (B)\n\n\n\n\n      (C)                  (D)\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-023", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "唐宣宗時，相國令狐綯以故事訪於溫岐，對以「其事出《南華》1。」\n且曰：「非僻書也。或冀相公燮理 2 之暇，時宜覽古。」綯怒。\n根據這段文字，下列敘述何者正確？\n", "options": ["令狐綯向溫岐求問無解，故勃然大怒        1.《南華》：指《莊子》", "令狐綯因施政遇到困難，找溫岐商量        2.燮理：治理國事", "溫岐回答問題後，勸令狐綯要多讀書", "溫岐以《南華》中的故事指正令狐綯"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 23, "raw_text": "23.      唐宣宗時，相國令狐綯以故事訪於溫岐，對以「其事出《南華》1。」\n       且曰：「非僻書也。或冀相公燮理 2 之暇，時宜覽古。」綯怒。\n\n      根據這段文字，下列敘述何者正確？\n                                 \n      (A)令狐綯向溫岐求問無解，故勃然大怒        1.《南華》：指《莊子》\n      (B)令狐綯因施政遇到困難，找溫岐商量        2.燮理：治理國事\n      (C)溫岐回答問題後，勸令狐綯要多讀書\n      (D)溫岐以《南華》中的故事指正令狐綯\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-024", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "臺北的王小姐要以右列信封寄信給高雄的陳先生，\n其中格式有誤，下列修改何者正確？", "options": ["郵票應貼在信封右上角", "左右欄書寫的地址應對調", "左欄的「王緘」二字應改為「王寄」", "中欄的啟封詞「大啟」應改為「敬啟」"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 24, "raw_text": "24. 臺北的王小姐要以右列信封寄信給高雄的陳先生，\n    其中格式有誤，下列修改何者正確？\n    (A)郵票應貼在信封右上角\n    (B)左右欄書寫的地址應對調\n    (C)左欄的「王緘」二字應改為「王寄」\n    (D)中欄的啟封詞「大啟」應改為「敬啟」\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-025", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列文句中的「如」字，何者與「如期完成」的「如」字意思相同？", "options": ["坐須臾，沛公起「如」廁", "弗如也！吾與汝弗「如」也", "朝與下大夫言，侃侃「如」也", "有不「如」法者，以付廷尉，依律治之"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 25, "raw_text": "25.   下列文句中的「如」字，何者與「如期完成」的「如」字意思相同？\n      (A)坐須臾，沛公起「如」廁\n      (B)弗如也！吾與汝弗「如」也\n      (C)朝與下大夫言，侃侃「如」也\n      (D)有不「如」法者，以付廷尉，依律治之\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-026", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "蘇東坡自述 ：「自今日以往，不過一爵一肉。有尊客，盛饌則三之，可損不可增。\n有召我者，預以此先之，主人不從而過是者，乃止。一曰安分以養福，二曰寬胃以\n養氣，三曰省費以養財。」根據這段文字，下列何者最符合東坡的飲食原則？", "options": ["對己待客，飲食皆須有所節制", "招待尊客，最少須準備三道盛饌", "受邀作客時，抱持客隨主便的態度", "宴請賓客前，必先告知自家飲食原則"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 26, "raw_text": "26. 蘇東坡自述 ：「自今日以往，不過一爵一肉。有尊客，盛饌則三之，可損不可增。\n    有召我者，預以此先之，主人不從而過是者，乃止。一曰安分以養福，二曰寬胃以\n    養氣，三曰省費以養財。」根據這段文字，下列何者最符合東坡的飲食原則？\n    (A)對己待客，飲食皆須有所節制\n    (B)招待尊客，最少須準備三道盛饌\n    (C)受邀作客時，抱持客隨主便的態度\n    (D)宴請賓客前，必先告知自家飲食原則\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-027", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列文句，何者有語病？", "options": ["車子駛向這塊久別之地，我不禁有近鄉情怯之感", "昂首望去，眼前是一片萬丈深淵，令人心生畏懼", "忙碌的現代人無暇尋幽訪勝，更不可能遁跡深山", "黑暗中，漫長的靜默裡，父親長長地嘆了一口氣"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 27, "raw_text": "27.   下列文句，何者有語病？\n      (A)車子駛向這塊久別之地，我不禁有近鄉情怯之感\n      (B)昂首望去，眼前是一片萬丈深淵，令人心生畏懼\n      (C)忙碌的現代人無暇尋幽訪勝，更不可能遁跡深山\n      (D)黑暗中，漫長的靜默裡，父親長長地嘆了一口氣\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-chinese-028", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-106-chinese", "question_type": "single_choice", "question_text": "下列選項「」中的字，何者讀音前後相同？", "options": ["青雲直「上」／平「上」去入", "個性倔「強」／「強」弩之末", "「伺」機而動／茶水「伺」候", "不堪負「荷」／「荷」槍實彈"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "97fdb0fabe32", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 28, "raw_text": "28.   下列選項「」中的字，何者讀音前後相同？\n      (A)青雲直「上」／平「上」去入\n      (B)個性倔「強」／「強」弩之末\n      (C)「伺」機而動／茶水「伺」候\n      (D)不堪負「荷」／「荷」槍實彈\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
